const a = [
  {"id":550,"text":"Which of the following conditions is recombinant erythropoietin indicated for?","explanation":null,"reference":"Guan XZ, Wang LL, Pan X, et al. Clinical indications of recombinant human erythropoietin in a single center: a 10-year retrospective study. Frontiers in Pharmacology. Published 2020. https://pubmed.ncbi.nlm.nih.gov/32848738/","responses":[{"text":"Megaloblastic anemia","correct":false,"visible":false},{"text":"Anemia due to thalassemia","correct":false,"visible":false},{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Anemia due to chronic kidney disease","correct":true,"visible":false},{"text":"Anemia due to malnutrition","correct":false,"visible":false}]},{"id":551,"text":"A patient may present with hemolytic anemia because of genetic mutations in protein synthesis. What is the most common inherited disorder causing anemia in humans in this connection?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 635.","responses":[{"text":"Autoimmune hemolytic anemia","correct":false,"visible":false},{"text":"Glucose-6-phosphate dehydrogenase (G6PD) deficiency","correct":false,"visible":false},{"text":"Thalassemia syndrome","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":true,"visible":false}]},{"id":564,"text":"What is the advantage of fingerprinting?","explanation":null,"reference":"Dow lecture slides: Hematology module, Forensic Medicine lecture slides, Personal Identity III, \"Galtonage or Dactylography I.E. Fingerprints.\"","responses":[{"text":"No special training required","correct":false,"visible":false},{"text":"It is applicable for all age groups","correct":false,"visible":false},{"text":"It is applicable for all people","correct":false,"visible":false},{"text":"It enables absolute identification of an individual","correct":true,"visible":false},{"text":"It does not require any special and expensive instruments","correct":false,"visible":false}]},{"id":567,"text":"What is the single best test to confirm iron deficiency anemia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 941.","responses":[{"text":"Plasma iron level","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false},{"text":"Total iron-binding capacity (TIBC)","correct":false,"visible":false},{"text":"Transferrin saturation","correct":false,"visible":false},{"text":"Plasma ferritin levels","correct":true,"visible":false}]},{"id":571,"text":"A 9-year-old boy is brought to the outpatient department after he developed prominent bruises on his extremities. There is a history of a recent viral infection. Labs show normal values of both prothrombin time (PT) and activated partial thromboplastin time (aPTT). What is the most likely diagnosis?","explanation":null,"reference":"Kahane, S et al. “Detection of anti-platelet antibodies in patients with idiopathic thrombocytopenic purpura (ITP) and in patients with rubella and herpes group viral infections.” Clinical and experimental immunology vol. 44,1 (1981): 49-56.","responses":[{"text":"Bone marrow aplasia","correct":false,"visible":false},{"text":"Vitamin C deficiency","correct":false,"visible":false},{"text":"Anti-platelet antibodies","correct":true,"visible":false},{"text":"Von-Willebrand disease","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false}]},{"id":596,"text":"A 30-year-old lady received 6 units of blood and developed carpopedal spasm and twitching in her hands, along with flushing of the face. What can be given to relieve her condition?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 663.","responses":[{"text":"Intravenous normal saline","correct":false,"visible":false},{"text":"Intravenous water","correct":false,"visible":false},{"text":"Intravenous calcium gluconate","correct":true,"visible":false},{"text":"Intravenous 5% dextrose","correct":false,"visible":false},{"text":"Intravenous diazepam","correct":false,"visible":false}]},{"id":603,"text":"A 25-year-old female with a history of two miscarriages develops deep vein thrombosis (DVT) in her leg. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 457.","responses":[{"text":"Antiphospholipid syndrome","correct":true,"visible":false},{"text":"Behcet's syndrome","correct":false,"visible":false},{"text":"Rheumatoid arthritis","correct":false,"visible":false},{"text":"Systemic lupus erythematosus","correct":false,"visible":false},{"text":"Overlap syndrome","correct":false,"visible":false}]},{"id":611,"text":"Which of the following agents is a potent iron chelator?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 428.","responses":[{"text":"Succimer","correct":false,"visible":false},{"text":"Ferrous gluconate","correct":false,"visible":false},{"text":"Unithiol","correct":false,"visible":false},{"text":"Deferoxamine","correct":true,"visible":false},{"text":"Ferrous sulfate","correct":false,"visible":false}]},{"id":614,"text":"A 35-year-old man with a history of intravenous (IV) drug abuse has generalized lymphadenopathy. Which of the following tests would help in finding the cause of his lymphadenopathy?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 312. (2) Hematology module, Medicine lecture slides, Topic: Approach to a patient of lymphadenopathy with and without splenomegaly, Sub-topic: location.","responses":[{"text":"HIV serology","correct":true,"visible":false},{"text":"Histopathology","correct":false,"visible":false},{"text":"Ultrasonography","correct":false,"visible":false},{"text":"Complete blood count (CBC)","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false}]},{"id":620,"text":"Stunted and notched upper central incisors are most likely to be found in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 381.","responses":[{"text":"Congenital syphilis","correct":true,"visible":false},{"text":"Scurvy","correct":false,"visible":false},{"text":"Rickets","correct":false,"visible":false},{"text":"Fetal alcohol syndrome","correct":false,"visible":false},{"text":"Plummer vinson syndrome","correct":false,"visible":false}]},{"id":652,"text":"A person with polycythemia vera will have which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015:  619.","responses":[{"text":"Yellow and jaundiced","correct":false,"visible":false},{"text":"Anemia","correct":false,"visible":false},{"text":"Pink in colour","correct":false,"visible":false},{"text":"Well oxygenated","correct":false,"visible":false},{"text":"Cyanotic due to sluggish blood flow","correct":true,"visible":false}]},{"id":653,"text":"A 65-year-old male presents with a 2-month history of fever and weight loss. On examination, the spleen is palpable 6 cm below the left costal margin. Complete blood count (CBC) reveals leukocytes=125x10⁹/L, hemoglobin=7.0 gm/dL and platelets= 510X10³/µL . He is diagnosed with chronic myeloid leukemia. Which of the following defects is present in chronic myeloid leukemia?","explanation":"The specific genetic defect associated with CML is the **t(9:22)** translocation, also known as the Philadelphia chromosome. This translocation results in the formation of the BCR-ABL fusion gene, which encodes a constitutively active tyrosine kinase. This abnormal kinase activity drives the uncontrolled proliferation of myeloid cells seen in CML.\r\n\r\nThe presence of the t(9:22) translocation is a hallmark of CML and is essential for its diagnosis. It is also a therapeutic target for drugs like tyrosine kinase inhibitors (TKIs), such as imatinib, which have revolutionized the treatment of this leukemia.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 616.","responses":[{"text":"t(9:11)","correct":false,"visible":false},{"text":"t(9:22)","correct":true,"visible":false},{"text":"t(8:21)","correct":false,"visible":false},{"text":"t(11:21)","correct":false,"visible":false},{"text":"t(15:17)","correct":false,"visible":false}]},{"id":654,"text":"An eye witness claims the victims death occurred about 12 hours ago. Which of the finding will confirm the statement?","explanation":null,"reference":"(1) Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 157-159.\r\n\r\n(2) Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 140.","responses":[{"text":"Rigor mortis present all over","correct":true,"visible":false},{"text":"Lividity fully developed and fixed","correct":false,"visible":false},{"text":"Increase in chemical constituents of cerebrospinal fluid (CSF)","correct":false,"visible":false},{"text":"Greenish patch over caecum","correct":false,"visible":false},{"text":"Rise in potassium content of vitreous humor","correct":false,"visible":false}]},{"id":656,"text":"How many subtypes is Hodgkin lymphoma is divided into?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 609.","responses":[{"text":"Four subtypes","correct":false,"visible":false},{"text":"Two subtypes","correct":false,"visible":false},{"text":"Three subtypes","correct":false,"visible":false},{"text":"Five subtypes","correct":true,"visible":false},{"text":"Ten subtypes","correct":false,"visible":false}]},{"id":657,"text":"Putrefaction is said to be colliquative when there is which of the following?","explanation":null,"reference":"Dow Lecture Slides Hematology module, Forensic Medicine lecture slides, Death I, \"Putrefaction.\"","responses":[{"text":"Colour change at right iliac fossa","correct":false,"visible":false},{"text":"Tissue conversion into solid mass","correct":false,"visible":false},{"text":"Distention of abdominal cavity","correct":false,"visible":false},{"text":"Swollen, puffy, bloated face","correct":false,"visible":false},{"text":"Appearance of maggots","correct":true,"visible":false}]},{"id":658,"text":"Conversion of plasminogen to plasmin is inhibited by which of the following?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 445.","responses":[{"text":"Heparin","correct":false,"visible":false},{"text":"Alteplase","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Aminocaproic acid","correct":true,"visible":false},{"text":"Streptokinase","correct":false,"visible":false}]},{"id":659,"text":"A 2-year-old male child presented in emergency with sudden onset of jaundice and cola-colored urine since last night. He was put on antimalarial two days back for suspected malaria. On examination in addition to jaundice, he has anemia and splenomegaly without hepatomegaly or lymphadenopathy. His blood pressure is 80/50 mmHg, pulse rate 110/min, and no edema. What test will confirm \r\n a diagnosis?","explanation":null,"reference":"Beutler E, Duparc S; G6PD Deficiency Working Group. Glucose-6-phosphate dehydrogenase deficiency and antimalarial drug development. Am J Trop Med Hyg. 2007 Oct;77(4):779-89. https://pubmed.ncbi.nlm.nih.gov/17978087/","responses":[{"text":"Liver function test","correct":false,"visible":false},{"text":"Osmotic fragility test","correct":false,"visible":false},{"text":"G6PD levels in red blood cells","correct":true,"visible":false},{"text":"Hemoglobin electrophoresis","correct":false,"visible":false},{"text":"Urine D/R","correct":false,"visible":false}]},{"id":660,"text":"Which of the following antibodies is cold-type hemolytic anemia due to?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 644.","responses":[{"text":"IgM antibodies","correct":true,"visible":false},{"text":"IgG antibodies","correct":false,"visible":false},{"text":"IgD antibodies","correct":false,"visible":false},{"text":"IgA antibodies","correct":false,"visible":false},{"text":"IgE antibodies","correct":false,"visible":false}]},{"id":661,"text":"Maximum number of Reed-Sternberg cells are seen in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 609.","responses":[{"text":"Lymphocyte predominant Hodgkin lymphoma","correct":false,"visible":false},{"text":"Lymphocyte depleted Hodgkin lymphoma","correct":true,"visible":false},{"text":"Burkitt Lymphoma","correct":false,"visible":false},{"text":"Nodular sclerosis Hodgkin lymphoma","correct":false,"visible":false},{"text":"Mixed cellularity Hodgkin lymphoma","correct":false,"visible":false}]},{"id":662,"text":"The levels of protein C and protein S depend on which vitamin?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 121.","responses":[{"text":"Vitamin K","correct":true,"visible":false},{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin D","correct":false,"visible":false},{"text":"Vitamin C","correct":false,"visible":false}]},{"id":663,"text":"What number of teeth are in a eight-year-old child's mouth?","explanation":null,"reference":null,"responses":[{"text":"24","correct":true,"visible":false},{"text":"20","correct":false,"visible":false},{"text":"16","correct":false,"visible":false},{"text":"30","correct":false,"visible":false},{"text":"12","correct":false,"visible":false}]},{"id":664,"text":"Essentially all endemic forms of Burkitt lymphoma are associated with which pathogen?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 327.","responses":[{"text":"HCV","correct":false,"visible":false},{"text":"EBV","correct":true,"visible":false},{"text":"HTCL-I","correct":false,"visible":false},{"text":"HIV","correct":false,"visible":false},{"text":"HBV","correct":false,"visible":false}]},{"id":665,"text":"The process of decomposition in the air is twice as rapid as in water and eight times as rapid as in the soil this is called?","explanation":null,"reference":"Shedge R, Krishan K, Warrier V, Kanchan T. Postmortem Changes. In: StatPearls. StatPearls Publishing; 2022. Accessed March 31, 2022. http://www.ncbi.nlm.nih.gov/books/NBK539741/","responses":[{"text":"Casper's dictum","correct":true,"visible":false},{"text":"Newton law","correct":false,"visible":false},{"text":"Locard's exchange principle","correct":false,"visible":false},{"text":"Siphon principle","correct":false,"visible":false},{"text":"Fudin's principle","correct":false,"visible":false}]},{"id":667,"text":"Polycythemia vera is strongly associated with an activating point mutation in which of the following genes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 616.","responses":[{"text":"Tyrosine kinase ABL","correct":false,"visible":false},{"text":"p53","correct":false,"visible":false},{"text":"Tyrosine kinase JAK2","correct":true,"visible":false},{"text":"Tyrosine kinase JAKI","correct":false,"visible":false},{"text":"Tyrosine kinase","correct":false,"visible":false}]},{"id":668,"text":"A young female presents with a palpable cervical lymph node, and in her biopsy reveals Reed- Sternberg's cells. These cells are derived from which of the following cell types?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 615.","responses":[{"text":"Plasma cells","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"T-lymphocytes","correct":false,"visible":false},{"text":"ß-lymphocytes","correct":true,"visible":false},{"text":"Eosinophil","correct":false,"visible":false}]},{"id":669,"text":"Basophil leukocytosis is an indication for:","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 584.","responses":[{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Myeloproliferative disorder","correct":true,"visible":false},{"text":"Chronic infection","correct":false,"visible":false},{"text":"Acute myelogenous leukemia","correct":false,"visible":false},{"text":"Stenle inflammation","correct":false,"visible":false}]},{"id":670,"text":"Which of the following is responsible to facilitate absorption of oral iron preparations?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 651.","responses":[{"text":"Phosphoric acid","correct":false,"visible":false},{"text":"Presence of food in stomach","correct":false,"visible":false},{"text":"Antacids","correct":false,"visible":false},{"text":"Tetracyclines","correct":false,"visible":false},{"text":"Ascorbic acid","correct":true,"visible":false}]},{"id":671,"text":"A 6-year-old child, diagnosed with hereditary spherocytosis, complained of increased frequency of blood transfusions. Blood complete picture shows Hb=6.5 gm/dL, reticulocyte count=20%, TLC=4000/mm³, platelets=100,000/mm³. What will be the most appropriate treatment for this child?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 633.","responses":[{"text":"Corticosteroids with antithymhocytic globulin","correct":false,"visible":false},{"text":"Splenectomy","correct":true,"visible":false},{"text":"Bone marrow transplant","correct":false,"visible":false},{"text":"Hydroxyurea","correct":false,"visible":false},{"text":"Repeated transfusions with iron chelation","correct":false,"visible":false}]},{"id":672,"text":"A child is diagnosed with non-Hodgkin lymphoma. He has generalized lymphadenopathy. Chest X-ray shows a mediastinal mass and CT abdomen shows enlarged, multiple mesentric, and para aortic lymph nodes. What is the most likely stage of the disease?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 962.","responses":[{"text":"Stage III","correct":true,"visible":false},{"text":"Stage I","correct":false,"visible":false},{"text":"Stage IV","correct":false,"visible":false},{"text":"Stage V","correct":false,"visible":false},{"text":"Stage II","correct":false,"visible":false}]},{"id":675,"text":"Which of the following groups of drugs is not used for the treatment of thrombosis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 445.","responses":[{"text":"Antifibrinolytics","correct":true,"visible":false},{"text":"Anticoagulants","correct":false,"visible":false},{"text":"Antiplatelet drugs","correct":false,"visible":false},{"text":"Thrombin inhibitors","correct":false,"visible":false},{"text":"Fibrinolytics","correct":false,"visible":false}]},{"id":695,"text":"Extravascular hemolysis occurs mainly in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 631.","responses":[{"text":"GIT","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Lymph node","correct":false,"visible":false},{"text":"Spleen","correct":true,"visible":false},{"text":"Blood vessels","correct":false,"visible":false}]},{"id":696,"text":"Hemoglobin (HbH) disease is caused by which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 641.","responses":[{"text":"Deletion of three alpha-globin genes","correct":true,"visible":false},{"text":"Deletion of beta-globin genes","correct":false,"visible":false},{"text":"Deletion of gamma-globin genes","correct":false,"visible":false},{"text":"Point mutation in a single alpha-globin gene","correct":false,"visible":false},{"text":"Deletion of delta-globin genes","correct":false,"visible":false}]},{"id":697,"text":"Systemic viral infection, particularly in children often produce which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 584.","responses":[{"text":"Acute lymphadenitis in inguinal region","correct":false,"visible":false},{"text":"Acute mesenteric adenitis","correct":false,"visible":false},{"text":"Acute lymphadenitis in axillary region","correct":false,"visible":false},{"text":"Acute generalized lymphadenopathy","correct":true,"visible":false},{"text":"Acute lymphadenitis in cervical region","correct":false,"visible":false}]},{"id":698,"text":"A 4-year-old girl presents with skin pallor for the past 3 days. One week ago she had a history of bloody diarrhea. Examination showed petechiae on the upper limbs. Laboratory studies revealed Hb 7.1 g/dl, reticulocytes 14%, platelets 30x 109/L, and normal WBC count. The renal function is deranged. The peripheral smear features numerous schistocytes and occasional nucleated RBC. Given the findings, which of the following bacteria is involved in the pathophysiology of disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 790","responses":[{"text":"Salmonella typhi","correct":false,"visible":false},{"text":"Streptococcus pyogenes","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Helicobacter pylori","correct":false,"visible":false},{"text":"Shigella dysenteriae","correct":true,"visible":false}]},{"id":699,"text":"Stony hard lymph node is mostly suggestive of which of the following?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 291.","responses":[{"text":"Inflammation","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Lymphoma","correct":false,"visible":false},{"text":"Infection","correct":false,"visible":false},{"text":"Malignancy","correct":true,"visible":false}]},{"id":700,"text":"A 45-year-old man with acute myocardial infarction is given alteplase. Which statement best describes its effect?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 306.","responses":[{"text":"Inhibition of platelet thromboxane production","correct":false,"visible":false},{"text":"Inhibits synthesis of vitamin K-dependent coagulation factors","correct":false,"visible":false},{"text":"Prevents aggregation of adjacent platelets by blocking glycoprotein IIb/IIIa receptor","correct":false,"visible":false},{"text":"Blockade of ADP-platelet receptor","correct":false,"visible":false},{"text":"Rapidly activates plasmin","correct":true,"visible":false}]},{"id":701,"text":"A 2-year-old child comes to the hospital for circumcision. His two brothers also had bleeding diathesis. Which test should be done?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015:  663.","responses":[{"text":"D-dimers","correct":false,"visible":false},{"text":"Clotting time","correct":false,"visible":false},{"text":"aPTT","correct":true,"visible":false},{"text":"Bleeding time","correct":false,"visible":false},{"text":"Urea clot lysis test","correct":false,"visible":false}]},{"id":703,"text":"ABO incompatibility occurs in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 666.","responses":[{"text":"Post transfusion plupine","correct":false,"visible":false},{"text":"Transfusion of bacterial contaminated blood product","correct":false,"visible":false},{"text":"Febrile non-hemolytic transfusion reactions","correct":false,"visible":false},{"text":"Anaphylactic reaction","correct":false,"visible":false},{"text":"Acute hemolytic transfusion reactions","correct":true,"visible":false}]},{"id":704,"text":"Spontaneous bleeding becomes evident when the platelet count falls below which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 657.","responses":[{"text":"40,000 platelets per microliter blood","correct":false,"visible":false},{"text":"60,000 platelets per microliter blood","correct":false,"visible":false},{"text":"100,000 platelets per microliter blood","correct":false,"visible":false},{"text":"75,000 platelets per microliter blood","correct":false,"visible":false},{"text":"20,000 platelets per microliter blood","correct":true,"visible":false}]},{"id":705,"text":"A 45-year-old male who is bed-bound from paraplegia develops sudden shortness of breath. On examination, his right calf is found to be swollen and tender, a provisional diagnosis of deep vein thrombosis (DVT) and pulmonary embolism is made. What will be the single most sought diagnostic test?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 697-698.\r\n\r\n2) Klok FA, Mos ICM, Kroft LJM, de Roos A, Huisman MV. Computed tomography pulmonary angiography as a single imaging test to rule out pulmonary embolism. Current Opinion in Pulmonary Medicine. Published September 2011. https://pubmed.ncbi.nlm.nih.gov/21681098/","responses":[{"text":"Doppler venous ultrasonography","correct":false,"visible":false},{"text":"Echocardiography","correct":false,"visible":false},{"text":"Electrocardiography (ECG)","correct":false,"visible":false},{"text":"Computed tomography (CT) pulmonary angiography","correct":true,"visible":false},{"text":"X-ray chest","correct":false,"visible":false}]},{"id":706,"text":"A 30-year-old female admitted with anemic failure for which she received six units of stored whole blood. After 24 hours she develops twitching on the face and carpopedal spasm of hands. What is the best treatment option?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1105.","responses":[{"text":"Give her I/V slowly calcium gluconate infusion","correct":true,"visible":false},{"text":"Give her I/V diazepam","correct":false,"visible":false},{"text":"Give her I/V magnesium sulphate","correct":false,"visible":false},{"text":"Give her I/V 5% dextrose water","correct":false,"visible":false},{"text":"Give her I/V normal saline","correct":false,"visible":false}]},{"id":707,"text":"A 25-year-old female presents with sudden onset pain in the right upper limb on examination right upper limb is pale, cold, extremely tender with absent radial and brachial pulses on the right side. What is the likely diagnosis?","explanation":null,"reference":"Obara H, Matsubara K, Kitagawa Y. Acute Limb Ischemia. Ann Vasc Dis. 2018;11(4):443-448. doi:10.3400/avd.ra.18-00074. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6326052/.","responses":[{"text":"Myositis","correct":false,"visible":false},{"text":"Acute limb ischemia","correct":true,"visible":false},{"text":"Venous thrombosis","correct":false,"visible":false},{"text":"Osteomyelitis","correct":false,"visible":false},{"text":"Humerus fracture","correct":false,"visible":false}]},{"id":708,"text":"What is the most appropriate treatment for a 5-year-old child with hereditary spherocytosis, large spleen, with hemoglobin mostly remaining at 7-9gm/dl, and reticulocyte count at 12-15%?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 947.","responses":[{"text":"Hydroxyurea","correct":false,"visible":false},{"text":"Regular blood transfusions with deferral","correct":true,"visible":false},{"text":"Regular blood transfusions","correct":false,"visible":false},{"text":"Bone marrow transplant","correct":false,"visible":false},{"text":"Splenectomy","correct":false,"visible":false}]},{"id":709,"text":"For a functional platelet disorder, which of the following is a correct statement?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 434.","responses":[{"text":"Thrombocytopenia, PT and APTT will be normal","correct":false,"visible":false},{"text":"Normal platelet count, PT \u0026 APTT will be prolonged","correct":false,"visible":false},{"text":"Normal platelet count, APTT will be prolonged","correct":false,"visible":false},{"text":"Normal or low platelet count, PT \u0026 APTT will be normal","correct":true,"visible":false},{"text":"Thrombocytopenia, only PT will be prolonged","correct":false,"visible":false}]},{"id":735,"text":"Which investigation(s) is/are the first step investigating a case of thrombosis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 696, 722.","responses":[{"text":"Antiphospholipid antibodies","correct":false,"visible":false},{"text":"Lupus anticoagulant","correct":false,"visible":false},{"text":"D-dimers","correct":true,"visible":false},{"text":"Prothrombin time","correct":false,"visible":false},{"text":"Factor V Leiden","correct":false,"visible":false}]},{"id":771,"text":"A guy who shoots himself tends to get instantaneous rigor instead of rigor mortis. Which one of the following statements most likely signifies the difference between the two?","explanation":null,"reference":"1) Awan NR. Principle and Practice Of Forensic Medicine. 2nd ed. Zubair Book Depot; 2018: 135.\r\n\r\n2)  Hematology module; Forensics medicine slides; Topic: Death-1; Sub-topic: Instantaneous rigor mortis (cadaveric spasm).","responses":[{"text":"Muscle contraction is less marked in instantaneous rigor mortis","correct":false,"visible":false},{"text":"Primary relaxation is absent in instantaneous rigor mortis","correct":true,"visible":false},{"text":"Instantaneous rigor indicates time of death instead of mode of death","correct":false,"visible":false},{"text":"Instantaneous rigor affects all the muscles","correct":false,"visible":false},{"text":"Instantaneous rigor mortis is not immediate after the death","correct":false,"visible":false}]},{"id":780,"text":"Which of the following foods has the best iron absorption from the intestines?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 650.","responses":[{"text":"Pomegranate","correct":false,"visible":false},{"text":"Pulses","correct":false,"visible":false},{"text":"Red meat","correct":true,"visible":false},{"text":"Oranges","correct":false,"visible":false},{"text":"Mangoes","correct":false,"visible":false}]},{"id":781,"text":"What is the most common condition leading to disseminated intravascular coagulation (DIC) in hospitalized patients?","explanation":null,"reference":"Papageorgiou C, Jourdi G, Adjambri E, et al. Disseminated Intravascular Coagulation: An Update on Pathogenesis, Diagnosis, and Therapeutic Strategies. Clin Appl Thromb Hemost. 2018;24(9_suppl):8S-28S. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6710154/.","responses":[{"text":"Severe infection","correct":true,"visible":false},{"text":"Snake bite","correct":false,"visible":false},{"text":"Malignancy","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false},{"text":"Vascular aneurysms","correct":false,"visible":false}]},{"id":783,"text":"Which iron preparation can be given only by the intravenous route?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 424.","responses":[{"text":"Sodium ferrous gluconate complex","correct":false,"visible":false},{"text":"Iron fructose complex","correct":false,"visible":false},{"text":"Sodium ferric gluconate complex","correct":true,"visible":false},{"text":"Ferrous gluconate dessicated","correct":false,"visible":false},{"text":"Ferrous fumarate","correct":false,"visible":false}]},{"id":784,"text":"Which of the following is correct regarding nutritional anemia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 923.","responses":[{"text":"Most common cause is folate deficiency","correct":false,"visible":false},{"text":"It is a disease syndrome","correct":false,"visible":false},{"text":"Does not present with signs and symptms","correct":false,"visible":false},{"text":"Most common cause is iron deficiency","correct":true,"visible":false},{"text":"Cannot be recovered","correct":false,"visible":false}]},{"id":787,"text":"What is the most common chromosomal change in acute lymphoblastic leukemia (ALL)?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 591.","responses":[{"text":"t(14; 18)","correct":false,"visible":false},{"text":"Hyperploidy","correct":true,"visible":false},{"text":"t(11; 18)","correct":false,"visible":false},{"text":"Trisomy 12","correct":false,"visible":false},{"text":"t(8; 14)","correct":false,"visible":false}]},{"id":789,"text":"Which of the following inherited bleeding disorders almost always occurs in males?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 662.","responses":[{"text":"Von Willebrand disease","correct":false,"visible":false},{"text":"Factor VII deficiency","correct":false,"visible":false},{"text":"Hemophilia A","correct":true,"visible":false},{"text":"Factor XIII deficiency","correct":false,"visible":false},{"text":"Factor V deficiency","correct":false,"visible":false}]},{"id":791,"text":"A 25-year-old male presents to the clinic with easy fatigability and generalized weakness. On examination he has blood pressure (BP)=110/60 mm of Hg, looks pale, and has koilonychia. His complete blood count (CBC) shows: Hb=9.7 g/dl, MCV=69 fl, MCHC=26 g/dl. What is the most likely cause of anemia in this patient?","explanation":"The clinical presentation, including pallor, koilonychia (spoon-shaped nails), and fatigue, along with the laboratory findings of a low hemoglobin (Hb) level, microcytic anemia (low mean corpuscular volume or MCV), and decreased mean corpuscular hemoglobin concentration (MCHC), strongly suggest **iron deficiency** as the underlying cause. Koilonychia is a classic sign associated with severe and chronic iron deficiency anemia.\r\n\r\nIt is often due to chronic blood loss, inadequate dietary iron intake, or poor iron absorption. In this case, the microcytic, hypochromic red blood cells seen in the blood smear, along with the clinical features, align with a diagnosis of iron deficiency anemia.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 652.","responses":[{"text":"Thalassemia minor","correct":false,"visible":false},{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":true,"visible":false},{"text":"Thalassemia major","correct":false,"visible":false},{"text":"Sideroblastic anemia","correct":false,"visible":false}]},{"id":794,"text":"Which of the following triggers the extrinsic clotting mechanism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 496.","responses":[{"text":"Platelets","correct":false,"visible":false},{"text":"Thromboplastin","correct":true,"visible":false},{"text":"Red blood cells","correct":false,"visible":false},{"text":"White blood cells","correct":false,"visible":false},{"text":"Adenosine","correct":false,"visible":false}]},{"id":796,"text":"Corticosteroid-induced immunosuppression involves which of the following?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 627.","responses":[{"text":"Modification of T cell mediated response","correct":false,"visible":false},{"text":"B-lymphocyte activation inhibition","correct":false,"visible":false},{"text":"Decreased production of interleukins","correct":false,"visible":false},{"text":"All of these","correct":true,"visible":false},{"text":"Mast cell stabilization","correct":false,"visible":false}]},{"id":803,"text":"A 64-year-old male presents to the hospital with excruciating back pain, His erythrocyte sedimentation rate (ESR) and creatinine levels are markedly raised. The clinical diagnosis made by the physician is multiple myeloma. What will be the most characteristic findings on his serum protein electrophoresis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 600.","responses":[{"text":"Polyclonal broad band in gamma region","correct":false,"visible":false},{"text":"Single sharp discrete band in gamma region","correct":true,"visible":false},{"text":"Single sharp band in alpha region","correct":false,"visible":false},{"text":"Single sharp band in beta 2 region","correct":false,"visible":false},{"text":"Single sharp band in albumin region","correct":false,"visible":false}]},{"id":804,"text":"The subdivision of lymphomas into Hodgkin's and Non-Hodgkin's lymphomas is based on the\r\nhistological presence of which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 607.","responses":[{"text":"B-cells","correct":false,"visible":false},{"text":"Reed–Sternberg cells","correct":true,"visible":false},{"text":"Kupffer cells","correct":false,"visible":false},{"text":"Natural killer cells (NK-cells)","correct":false,"visible":false},{"text":"T-cells","correct":false,"visible":false}]},{"id":805,"text":"In myeloproliferative disorders, there is a proliferation of which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 616.","responses":[{"text":"Myeloid progenitors","correct":true,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Eosinophils","correct":false,"visible":false},{"text":"Monocytes","correct":false,"visible":false}]},{"id":806,"text":"A 45-year-old male presents with a 2-month history of fever and weight loss. On examination, massive splenomegaly is observed. Complete blood count (CBC) reveals leukocyte count=165x10⁹/L, hemoglobin= 9.0 gm/dL and platelets=510 X10³/µL . He is diagnosed with chronic myeloid leukemia. Which of the following molecular defects is present in chronic myeloid leukemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 616.","responses":[{"text":"c-Myc gene fusion","correct":false,"visible":false},{"text":"BCL6 gene fusion","correct":false,"visible":false},{"text":"BCR-ABL gene fusion","correct":true,"visible":false},{"text":"RAR alpha (RARA) gene fusion","correct":false,"visible":false},{"text":"p53 gene mutation","correct":false,"visible":false}]},{"id":832,"text":"An 8-year-old child is brought to the hospital with complaints of fever for 2 months along with hepatomegaly and splenomegaly. Investigations show the following: Hb=4.8 gm/dl, TLC=1700/HPF, platelets=38000. Peripheral smear shows microcytic anemia with blast cells. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 592.","responses":[{"text":"Hemolytic anemia","correct":false,"visible":false},{"text":"Sepsis/disseminated intravascular coagulation (DIC)","correct":false,"visible":false},{"text":"Typhoid fever","correct":false,"visible":false},{"text":"Malaria","correct":false,"visible":false},{"text":"Acute leukemia","correct":true,"visible":false}]},{"id":833,"text":"For the purpose of determining age and sex from the skeleton of an unknown dead body, maximum information can be obtained by examining which of the following?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 64.","responses":[{"text":"Metacarpals","correct":false,"visible":false},{"text":"Ribs","correct":false,"visible":false},{"text":"Vertebrae","correct":false,"visible":false},{"text":"Radius and ulna","correct":false,"visible":false},{"text":"Skull and mandible","correct":true,"visible":false}]},{"id":834,"text":"A fresh victim of a road traffic accident is brought to the emergency department but lost his life on the\r\nway to the hospital. To confirm his death, the body is examined for all immediate signs of death. Which of\r\nthe following is an immediate sign of death?","explanation":null,"reference":"Awan NR. Principle and Practice Of Forensic Medicine. 2nd ed. Zubair Book Depot; 2018: 132.","responses":[{"text":"Secondary relaxation","correct":false,"visible":false},{"text":"Rigor Mortis","correct":false,"visible":false},{"text":"Primary relaxation","correct":true,"visible":false},{"text":"Algor mortis","correct":false,"visible":false},{"text":"Postmortem lividity","correct":false,"visible":false}]},{"id":835,"text":"A 22-year-old woman attends an antenatal booking appointment. She has had previous 3 miscarriages. She has mouth ulcers and joint pains and is evaluated for arthritis/ arthralgia. Which single pair of results are most likely to confirm the underlying cause of her symptoms?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 480.","responses":[{"text":"Increased erythrocyte sedimentation rate (ESR) and rheumatoid factor","correct":false,"visible":false},{"text":"Decrease hemoglobin and increased reticulocytes","correct":false,"visible":false},{"text":"Decreased hemoglobin and decreased mean corpuscular volume (MCV)","correct":false,"visible":false},{"text":"Increased lactate dehydrogenase (LDH) and increased bilirubin","correct":false,"visible":false},{"text":"Increased activated partial thromboplastin time (aPTT) and decreased platelets","correct":true,"visible":false}]},{"id":861,"text":"The dead body of a young female is recovered from her house hanging from a fan. On examination it is seen that post mortem lividity in lower limbs is fully developed and fixed. If, in the dead body, the post mortem lividity does not blanch on applying pressure, what will be the probable time elapsed since her death?","explanation":null,"reference":"Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 120, 154.","responses":[{"text":"6-8 hours","correct":true,"visible":false},{"text":"10-12 hours","correct":false,"visible":false},{"text":"3-6 hours","correct":false,"visible":false},{"text":"0-3 hours","correct":false,"visible":false},{"text":"1-3 hours","correct":false,"visible":false}]},{"id":862,"text":"Tests for coagulation profile usually include; bleeding time, clotting time, prothrombin time (PT) and\r\nactivated partial prothrombin time (aPTT). Prolonged bleeding time with normal PT and APTT is indicative\r\nof which of the following conditions?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 433-435.","responses":[{"text":"Von-Willebrand disease","correct":false,"visible":false},{"text":"Thrombocytopenia","correct":true,"visible":false},{"text":"Idiopathic thrombocytopenic purpura","correct":false,"visible":false},{"text":"Vascular disorders","correct":false,"visible":false},{"text":"Hemophilia","correct":false,"visible":false}]},{"id":880,"text":"The process of margination of neutrophils is mediated by the reaction between which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 13.","responses":[{"text":"Integrin and interleukin-7 (IL-7)","correct":false,"visible":false},{"text":"Gamma interferon and integrin","correct":false,"visible":false},{"text":"Intracellular adhesion molecule-I and chemokines","correct":false,"visible":false},{"text":"Selectins and integrins","correct":true,"visible":false},{"text":"Integrin and major basic protein","correct":false,"visible":false}]},{"id":881,"text":"A 72-year-old man is brought to the emergency department with sudden onset of acute arterial occlusions of the right lower limb leading to gangrene of the lower leg and foot. He has lens subluxation and a long tapering finger. What is the most probable cause of this acute arterial occlusion?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 50.","responses":[{"text":"Homocysteinemia","correct":true,"visible":false},{"text":"Protein C deficiency","correct":false,"visible":false},{"text":"Factor V leiden mutant gene","correct":false,"visible":false},{"text":"Polycythemia vera","correct":false,"visible":false},{"text":"Antiphospholipid antibody syndrome","correct":false,"visible":false}]},{"id":882,"text":"What is the replacement source in the therapy of hemophilia A?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 663.","responses":[{"text":"Recombinant factor VIII products","correct":true,"visible":false},{"text":"Recombinant factor VII A","correct":false,"visible":false},{"text":"Fresh frozen plasma","correct":false,"visible":false},{"text":"Prothrombrin complex concentrates","correct":false,"visible":false},{"text":"Vitamin K","correct":false,"visible":false}]},{"id":883,"text":"A 10-year-old child with a known case of thalassemia major requires red cell transfusion every month, since the age of one year. For the last 5 to 6 months, he develops urticarial rashes during transfusion. What\r\nwill be an appropriate step for management?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 668.","responses":[{"text":"Prior to transfusion, give him one shot of steroid","correct":false,"visible":false},{"text":"Transfuse whole blood","correct":false,"visible":false},{"text":"Transfuse washed red blood cells","correct":false,"visible":false},{"text":"Transfuse Rh-negative blood","correct":false,"visible":false},{"text":"Prior to transfusion, give him antihistamine and antipyretic drugs","correct":true,"visible":false}]},{"id":884,"text":"What is the cephalic index?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 57.","responses":[{"text":"The ratio of the maximum breadth of the skull and anterioposterior length of skull","correct":true,"visible":false},{"text":"Sum of the maximum breadth of the skull and the maximum length of skull","correct":false,"visible":false},{"text":"Maximum anteroposterior length of skull","correct":false,"visible":false},{"text":"The maximum transverse breadth of skull","correct":false,"visible":false},{"text":"Superimposition technique","correct":false,"visible":false}]},{"id":885,"text":"A decapitated dead body of a male is brought for autopsy. What will be the most important part of an autopsy in this case for further identification?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 84.","responses":[{"text":"Taking photographs","correct":false,"visible":false},{"text":"Preservation of 1st vertebra of the body distal to the cut","correct":false,"visible":false},{"text":"Taking bone marrow for DNA fingerprinting","correct":false,"visible":false},{"text":"Taking fingerprints of the body","correct":true,"visible":false},{"text":"Taking poor prints","correct":false,"visible":false}]},{"id":886,"text":"Which of the following best suits the definition of hemolysis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 631.","responses":[{"text":"Premature destruction of red blood cells (RBCs)","correct":true,"visible":false},{"text":"Loss of blood via bleeding","correct":false,"visible":false},{"text":"Peripheral destruction of platelets","correct":false,"visible":false},{"text":"Extravasation of blood in skin","correct":false,"visible":false},{"text":"Under production of red blood cells","correct":false,"visible":false}]},{"id":887,"text":"What is the prime objective in bone marrow transplantation?","explanation":null,"reference":"Khaddour K, Hana CK, Mewawalla P. Hematopoietic stem cell transplantation. In: StatPearls. StatPearls Publishing; 2022. Accessed April 10, 2022. http://www.ncbi.nlm.nih.gov/books/NBK536951/","responses":[{"text":"Get rid of the primary disease","correct":true,"visible":false},{"text":"Make patient pancytopenic","correct":false,"visible":false},{"text":"To inhibit graft versus host disease (GVHD)","correct":false,"visible":false},{"text":"Chemotherapy to kill the malignant disease","correct":false,"visible":false},{"text":"To initiate graft versus host disease (GVHD)","correct":false,"visible":false}]},{"id":981,"text":"The indication for hematopoietic stem cell transplants does not include the following?","explanation":null,"reference":"Hołowiecki J. Indications for hematopoietic stem cell transplantation. Polskie Archiwum Medycyny Wewnetrznej. Published November 2008. https://pubmed.ncbi.nlm.nih.gov/19140570/","responses":[{"text":"Iron deficiency anemia","correct":true,"visible":false},{"text":"Hematologic malignancies","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Non-hematologic cancers","correct":false,"visible":false},{"text":"Thalassemia","correct":false,"visible":false}]},{"id":982,"text":"A boy is convicted of a criminal offense and the judge of the juvenile court orders to send him to a reformatory school. This is because his age is less than which of the following?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 76.","responses":[{"text":"15 years","correct":false,"visible":false},{"text":"14 years","correct":false,"visible":false},{"text":"16 years","correct":false,"visible":false},{"text":"18 years","correct":true,"visible":false},{"text":"17 years","correct":false,"visible":false}]},{"id":986,"text":"A male aged about 16-17 years is sent to confirm his age. Advisable single radiograph would be which of the following?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 72-73.","responses":[{"text":"Pelvis","correct":false,"visible":false},{"text":"Sternum","correct":false,"visible":false},{"text":"Skull","correct":false,"visible":false},{"text":"Wrist joint","correct":false,"visible":false},{"text":"Elbow joint","correct":true,"visible":false}]},{"id":987,"text":"A 70-year-old male presents to the hospital with severe backache. His investigations reveal Hb=7 gm/dl, creatinine=2 mg/dL, ESR= 110 mm/hour. What other finding is most likely to be found on investigations?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 63.","responses":[{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hypocalcemia","correct":false,"visible":false},{"text":"Raised serum alkaline phosphatase","correct":false,"visible":false},{"text":"Hypercalcemia","correct":true,"visible":false},{"text":"Bone scan showing increased uptake","correct":false,"visible":false}]},{"id":1046,"text":"A 10-year-old child who is otherwise healthy got a complete blood count done which showed Hb of 10 gm/dL, with hypochromic and microcytic red cell indices. Her pediatrician is assuming her to be a carrier of the beta-thalassemia trait. Which of the following tests will confirm her diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 44.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Hemoglobin electrophoresis","correct":true,"visible":false},{"text":"Osmotic fragility test","correct":false,"visible":false},{"text":"Blood culture","correct":false,"visible":false},{"text":"Schilling test","correct":false,"visible":false}]},{"id":1047,"text":"According to the expanded program of immunization (EPI), the second dose of the measles vaccine is recommended to be given at what age?","explanation":null,"reference":"Waheed MS. Expanded programme on immunization. World Health Organization - Regional Office for the Eastern Mediterranean. Accessed April 10, 2022. http://www.emro.who.int/pak/programmes/expanded-programme-on-immunization.html","responses":[{"text":"1 year","correct":false,"visible":false},{"text":"15 months","correct":true,"visible":false},{"text":"6 months","correct":false,"visible":false},{"text":"18 month","correct":false,"visible":false},{"text":"9 months","correct":false,"visible":false}]},{"id":1049,"text":"What is the best long term treatment in a patient with cerebrovascular accident (CVA) after arterial thrombosis with anti-phospholipid syndrome?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 444, 480.","responses":[{"text":"Physiotherapy","correct":false,"visible":false},{"text":"Warfarin","correct":true,"visible":false},{"text":"Lipid-lowering medicine","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Heparin","correct":false,"visible":false}]},{"id":1050,"text":"During the exhumation of an unidentified grave, a human skeleton was recovered.  What will be the most reliable bones to determine sex?","explanation":null,"reference":"(1) Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 64. \r\n\r\n(2) Ubelaker D. Bones: A Forensic Detective's Casebook. M. Evans \u0026 Company; 2000: 87.","responses":[{"text":"Skull","correct":false,"visible":false},{"text":"Pelvis","correct":false,"visible":false},{"text":"Skull and pelvis","correct":true,"visible":false},{"text":"Femur","correct":false,"visible":false},{"text":"Skull and femur","correct":false,"visible":false}]},{"id":1051,"text":"Which of the following is least likely to be a clinical feature of aplastic anemia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 654.","responses":[{"text":"Blood blisters in the mouth","correct":false,"visible":false},{"text":"Bleeding gums and epistaxis","correct":false,"visible":false},{"text":"Ecchymoses","correct":false,"visible":false},{"text":"Lymphadenopathy and hepatosplenomegaly","correct":true,"visible":false},{"text":"Bleeding with minimal trauma","correct":false,"visible":false}]},{"id":1052,"text":"Why is parenteral administration of folic acid not favored in patients?","explanation":null,"reference":null,"responses":[{"text":"Given orally because it is very tasty and hence the patient's compliance is very high","correct":false,"visible":false},{"text":"Its profound deficiency is not seen in human beings","correct":false,"visible":false},{"text":"It is well absorbed orally even in patients with malabsorption syndromes","correct":true,"visible":false},{"text":"It is rapidly metabolized and eliminated","correct":false,"visible":false},{"text":"It is too painful through the parenteral route","correct":false,"visible":false}]},{"id":1053,"text":"Different blood products are transfused in different clinical conditions. Which product is required if\r\na patient is bleeding actively and has deficiencies of multiple coagulation factors?","explanation":null,"reference":"Le, Tao, and Vikas Bhushan. First Aid for the USMLE Step 1 2022. 32nd ed., McGraw-Hill Education, 2022: 436.","responses":[{"text":"Fresh frozen plasma","correct":true,"visible":false},{"text":"Cryoprecipitate","correct":false,"visible":false},{"text":"Whole blood","correct":false,"visible":false},{"text":"Platelet","correct":false,"visible":false},{"text":"Packed red blood cells","correct":false,"visible":false}]},{"id":1054,"text":"A 22-year-old African American man went to the hospital to determine if he has sickle cell trait. Which one of the following laboratory tests can be used to detect the presence of hemoglobin S?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 638.","responses":[{"text":"Schillings test","correct":false,"visible":false},{"text":"Metabisulfite test","correct":true,"visible":false},{"text":"Coombs test","correct":false,"visible":false},{"text":"Glucose tolerance test","correct":false,"visible":false},{"text":"Osmotic fragility test","correct":false,"visible":false}]},{"id":1055,"text":"Which of the following antibodies are present in Bernard-Soulier syndrome?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 434.","responses":[{"text":"Glycoprotein IIa","correct":false,"visible":false},{"text":"Glycoprotein Ib antibodies","correct":true,"visible":false},{"text":"Glycoprotein IIa/IIIb antibodies","correct":false,"visible":false},{"text":"Glycoprotein Ib/IIIb antibodies","correct":false,"visible":false},{"text":"Platelet membrane phospholipids","correct":false,"visible":false}]},{"id":1077,"text":"In hemophilia, there is a prolongation of which of the following?","explanation":null,"reference":null,"responses":[{"text":"PT, aPTT, and bleeding time","correct":false,"visible":false},{"text":"Bleeding time","correct":false,"visible":false},{"text":"aPTT","correct":true,"visible":false},{"text":"PT and aPTT","correct":false,"visible":false},{"text":"PT","correct":false,"visible":false}]},{"id":1078,"text":"An 11-year-old child is diagnosed with acute lymphoblastic leukemia. Which of the following is the most important factor in classifying leukemia as a high-risk group?","explanation":null,"reference":null,"responses":[{"text":"Platelet count less than 50,000","correct":false,"visible":false},{"text":"Leukocyte count less than 1500","correct":false,"visible":false},{"text":"Age of the child between 1-10 years","correct":false,"visible":false},{"text":"Leukocyte count greater than 50,000","correct":true,"visible":false},{"text":"Hemoglobin less than 5 gm/dl","correct":false,"visible":false}]},{"id":1079,"text":"Which of the following is correct regarding the mixed cellularity variant of Hodgkin lymphoma?","explanation":null,"reference":null,"responses":[{"text":"Immunophenotype is not classical","correct":false,"visible":false},{"text":"The mononuclear variant of Reed-Sternberg cells is seen","correct":true,"visible":false},{"text":"Not associated with Epstein–Barr virus (EBV)","correct":false,"visible":false},{"text":"It is seen in 5% of cases","correct":false,"visible":false},{"text":"Monotonous cellular infiltrate is the hallmark","correct":false,"visible":false}]},{"id":1080,"text":"Epstein-Barr virus (EBV) is found in 30-40% of cases of which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 61.","responses":[{"text":"Acute myeloid leukemia","correct":false,"visible":false},{"text":"Hairy cell leukemia","correct":false,"visible":false},{"text":"Burkitt's lymphoma","correct":true,"visible":false},{"text":"Chronic myeloid leukemia","correct":false,"visible":false},{"text":"Kaposi's sarcoma","correct":false,"visible":false}]},{"id":1081,"text":"Immune cell antigen CD4 is associated with which of the following?","explanation":null,"reference":null,"responses":[{"text":"Natural killer cells","correct":false,"visible":false},{"text":"Mature T-cells","correct":false,"visible":false},{"text":"Thymocytes","correct":false,"visible":false},{"text":"Helper T-cells","correct":true,"visible":false},{"text":"Cytotoxic T-cells","correct":false,"visible":false}]},{"id":1082,"text":"Which of the following is not a presentation of a patient with a disorder of primary hemostasis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 31.","responses":[{"text":"Petechia","correct":false,"visible":false},{"text":"Hemarthrosis","correct":true,"visible":false},{"text":"Menorrhagia","correct":false,"visible":false},{"text":"Ecchymosis","correct":false,"visible":false},{"text":"Gum bleeding","correct":false,"visible":false}]},{"id":1108,"text":"A cord blood sample of an Rh-ve mother was sent for laboratory testing during labor. Which of the following would indicate the need for blood exchange transfusion?","explanation":null,"reference":"Goljan EF. Rapid Review Pathology. 5th ed. Elsevier, Inc; 2019: 416.","responses":[{"text":"Peripheral cells shows spherocytes","correct":false,"visible":false},{"text":"Reticulocyte is corrected to 7%","correct":true,"visible":false},{"text":"Indirect coombs test is weakly negative","correct":false,"visible":false},{"text":"Hemoglobin = 10 mg/dL","correct":false,"visible":false},{"text":"Serum bilirubin = 2.5 mg/dL","correct":false,"visible":false}]},{"id":1200,"text":"A patient has presented with iron deficiency anemia and was prescribed treatment with iron supplements. Which single test would show early response to the treatment?","explanation":null,"reference":"(1) Zhu A, Kaneshiro M, Kaunitz JD. Evaluation and treatment of iron deficiency anemia: a gastroenterological perspective. Digestive Diseases and Sciences. Published 2010. Accessed April 12, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2822907/\r\n\r\n(2) Iron deficiency anemia treatment \u0026 management: approach considerations, iron therapy, management of hemorrhage. Published online October 1, 2021. Accessed April 12, 2022. https://emedicine.medscape.com/article/202333-treatment","responses":[{"text":"Total Iron Binding capacity","correct":false,"visible":false},{"text":"Ferritin","correct":false,"visible":false},{"text":"Reticulocyte count","correct":true,"visible":false},{"text":"Blood Complete picture","correct":false,"visible":false},{"text":"Iron","correct":false,"visible":false}]},{"id":1201,"text":"Which one of the following statements is correct regarding vitamin B12 and folic acid?","explanation":null,"reference":null,"responses":[{"text":"Deficiency of either vitamin B12 or folic acid impairs DNA synthesis","correct":true,"visible":false},{"text":"Pernicious anemia should be treated with folic acid","correct":false,"visible":false},{"text":"Deficiency of folic acid is usually associated with neurological abnormalities","correct":false,"visible":false},{"text":"Lack of plasma transferrin causes the malabsorption of vitamin B12","correct":false,"visible":false},{"text":"To treat patient with a deficiency of intrinsic factor, vitamin B12 should be administered orally","correct":false,"visible":false}]},{"id":1202,"text":"In chronic myeloid leukemia, there is a predominant proliferation of which cells?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 58.","responses":[{"text":"Eosinophil precursors","correct":false,"visible":false},{"text":"Erythroid precursors","correct":false,"visible":false},{"text":"Basophil precursors","correct":true,"visible":false},{"text":"Granulocyte precursors","correct":false,"visible":false},{"text":"Eosinophil and myeloid precursors","correct":false,"visible":false}]},{"id":1203,"text":"Virchowis Node is pathological enlargement of:","explanation":null,"reference":null,"responses":[{"text":"Right jugulodigastric lymph node","correct":false,"visible":false},{"text":"Left jugulodigastric lymph node","correct":false,"visible":false},{"text":"Anterior Cervical Chain Lymph Node","correct":false,"visible":false},{"text":"Right Supra-Clavicular Lymph Node","correct":false,"visible":false},{"text":"Left Supra-Clavicular Lymph Node","correct":true,"visible":false}]},{"id":1204,"text":"Thrombotic thrombocytopenic purpura can be successfully treated by which of the following methods?","explanation":null,"reference":null,"responses":[{"text":"Dialysis which remove auto antibodies","correct":false,"visible":false},{"text":"Catheterization which remove plasma cells","correct":false,"visible":false},{"text":"Intravenous infusion which removes the antibodies","correct":false,"visible":false},{"text":"Platelet infusion which removes basal cells","correct":false,"visible":false},{"text":"Plasma exchange which remove auto antibodies","correct":true,"visible":false}]},{"id":1205,"text":"Why does sickling occur in sickle cell anemia?","explanation":null,"reference":null,"responses":[{"text":"Polycythaemia","correct":false,"visible":false},{"text":"Increase red cell counts","correct":false,"visible":false},{"text":"Low oxygen tension in tissues","correct":true,"visible":false},{"text":"Increased haemoglobin","correct":false,"visible":false},{"text":"RBC shape","correct":false,"visible":false}]},{"id":1206,"text":"In graft versus host (GVHD) disease, which organ is most commonly affected?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 802.","responses":[{"text":"Kidney","correct":false,"visible":false},{"text":"Skin","correct":false,"visible":false},{"text":"GIT","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false}]},{"id":1207,"text":"A 50-year-old male was diagnosed with a case of non-Hodgkin's lymphoma. His hemoglobin was 6 gm/dL. Peripheral smear shows anemia. Which type of anemia are non-Hodgkin lymphomas mostly associated with?","explanation":null,"reference":"Yasmeen T, Ali J, Khan K, Siddiqui N. Frequency and causes of anemia in Lymphoma patients. Pakistan Journal of Medical Sciences. Published 2019. Accessed April 11, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6408630/","responses":[{"text":"Anemia due to bone marrow infiltration","correct":false,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Anemia of chronic disease","correct":true,"visible":false},{"text":"Dry induced anemia","correct":false,"visible":false},{"text":"Autoimmune hemolytic anemia","correct":false,"visible":false}]},{"id":1210,"text":"Best indicator of air pollution is/are:","explanation":null,"reference":null,"responses":[{"text":"Smoke, suspended particles and SO2","correct":false,"visible":false},{"text":"Carbon monoxide","correct":false,"visible":false},{"text":"Sulphur dioxide","correct":false,"visible":false},{"text":"Particulate matter","correct":true,"visible":false},{"text":"Methane","correct":false,"visible":false}]},{"id":1211,"text":"A 21-year-old female has a history of recurrent blood transfusion. On examination she is anemic and her spleen is enlarged 6 cm below the left costal margin. Hb=7.3 g/dL, MCV=50 fL, reticulocyte count=3.5%. What is the likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Glucose-6-phosphate dehydrogenase deficiency","correct":false,"visible":false},{"text":"Hereditary spherocytosis","correct":false,"visible":false},{"text":"Pyruvate kinase deficiency","correct":false,"visible":false},{"text":"Sickle cell anemia","correct":false,"visible":false},{"text":"Thalassemia","correct":true,"visible":false}]},{"id":1213,"text":"Which of the following foods have best iron absorption from the intestine?","explanation":null,"reference":null,"responses":[{"text":"Mangoes","correct":false,"visible":false},{"text":"Pulses","correct":false,"visible":false},{"text":"Pomogrenate","correct":false,"visible":false},{"text":"Oranges","correct":false,"visible":false},{"text":"Red meat","correct":true,"visible":false}]},{"id":1227,"text":"Which of the following is the result of vitamin B12 deficiency?","explanation":null,"reference":"Le, Tao, and Vikas Bhushan. First Aid for the USMLE Step 1 2022. 32nd ed., McGraw-Hill Education, 2022: 428.","responses":[{"text":"Impaired collagen formation","correct":false,"visible":false},{"text":"Impaired coagulation","correct":false,"visible":false},{"text":"Impaired hemoglobin synthesis","correct":false,"visible":false},{"text":"Hematopoietic stem cell failure","correct":false,"visible":false},{"text":"Impaired DNA synthesis","correct":true,"visible":false}]},{"id":1228,"text":"A 1-year-old child is recently diagnosed with beta-thalassemia major. Which of the following will be the most characteristic findings on a peripheral film of the child?","explanation":null,"reference":null,"responses":[{"text":"Poikilocytosis, hypochromia, microcytosis, target cells, and fragmented red blood cells","correct":true,"visible":false},{"text":"Hyporchromia, microcytosis, and sickled cells","correct":false,"visible":false},{"text":"Bite cells, blister cells, and spherocytes","correct":false,"visible":false},{"text":"Microspherocytes, polychromasia, and nucleated red blood vells","correct":false,"visible":false},{"text":"Macro-ovalocytes with nuclear hypersegmentation","correct":false,"visible":false}]},{"id":1229,"text":"What is the primary mechanism by which heparin prevents coagulation of blood?","explanation":null,"reference":null,"responses":[{"text":"Direct inhibition of the conversion of prothrombin to thrombin","correct":false,"visible":false},{"text":"Inhibition of calcium","correct":false,"visible":false},{"text":"Inhibition of factors XIIa and XIIIa","correct":false,"visible":false},{"text":"Facilitation of antithrombin III mediated inhibition of factor Xa and thrombin","correct":true,"visible":false},{"text":"Activation of antithrombin III to inhibit factors IX and XI","correct":false,"visible":false}]},{"id":1230,"text":"A 5-year-old child with a known case of eczema also develops rhinitis and gets asthmatic with seasonal change. She is brought to the outpatient department and a complete blood count is advised. Which cell would be in high number is this case?","explanation":null,"reference":null,"responses":[{"text":"Neutrophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Eosinphils","correct":true,"visible":false},{"text":"Monocytes","correct":false,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false}]},{"id":1231,"text":"A dead body is brought to the mortuary for post mortem examination, having post mortem rigidity present in the whole body from head to toe. What is the estimated time since the death?","explanation":null,"reference":null,"responses":[{"text":"24-36 hours","correct":false,"visible":false},{"text":"36-48 hours","correct":false,"visible":false},{"text":"4-18 hours","correct":false,"visible":false},{"text":"12-24 hours","correct":true,"visible":false},{"text":"2-4 hours","correct":false,"visible":false}]},{"id":1232,"text":"What are the differentiating features of the female pelvis?","explanation":null,"reference":null,"responses":[{"text":"Obturator foramen is large","correct":false,"visible":false},{"text":"Sub-pubic angle V-shaped","correct":false,"visible":false},{"text":"Ischial tuberosity is inverted","correct":false,"visible":false},{"text":"Pre-auricular sulcus less prominent","correct":false,"visible":false},{"text":"Sub-pubic angle U-shaped, and obtuse","correct":true,"visible":false}]},{"id":1233,"text":"A 29-year-old female comes for a routine checkup as part of a pre-employment requirement. Her complete blood count reveals Hb= 10 gm/dL with microcytic hypochromic red cell indices. Assuming that she is a carrier of the beta-thalassemia trait, what will be the most likely findings on her hemoglobin electrophoresis to confirm her carrier status?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 416, 641. \r\n\r\n(2) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 44.","responses":[{"text":"Normal HbA and increased Hb A2 (3-5%)","correct":false,"visible":false},{"text":"Normal HbA and A2, but slightly increased HbF","correct":false,"visible":false},{"text":"Normal HbA and A2, but markedly increased HbF (\u003e90%)","correct":false,"visible":false},{"text":"Decreased HbA,and raised HbA2 and HbF","correct":true,"visible":false},{"text":"Normal HbA and increased Hb A2 (4-8%)","correct":false,"visible":false}]},{"id":1238,"text":"A 40-year-old male bed-bound from paraplegia is diagnosed with deep vein thrombosis (DVT) in his right leg. He develops a sudden onset of shortness of breath. A subsequent diagnosis of pulmonary embolism is made. What will be the most common initial electrocardiography (ECG) finding?","explanation":null,"reference":null,"responses":[{"text":"S1Q3T3 pattern","correct":false,"visible":false},{"text":"ST segment elevation","correct":false,"visible":false},{"text":"Right bundle branch block","correct":false,"visible":false},{"text":"Sinus tachycardia","correct":true,"visible":false},{"text":"Non-specific T wave inversion","correct":false,"visible":false}]},{"id":1240,"text":"A 20-year-old male is brought to the outpatient department with a history of painless cervical lymphadenopathy and a physician is suspecting malignancy. What is the key investigation required to get a diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 927.","responses":[{"text":"Fine needle aspiration (FNA)","correct":false,"visible":false},{"text":"Excisional biopsy of the node","correct":true,"visible":false},{"text":"Chest X-ray (CXR)","correct":false,"visible":false},{"text":"Erythrocyte sedimentation rate (ESR)","correct":false,"visible":false},{"text":"Complete blood count (CBC)","correct":false,"visible":false}]},{"id":1242,"text":"A 20-year-old male presents to the outpatient department with a history of fever and night sweats for the past two months. On examination, multiple cervical lymph nodes are palpable which are painless and matted. Which of the following is the single best diagnostic option?","explanation":null,"reference":null,"responses":[{"text":"Mantoux test","correct":false,"visible":false},{"text":"High levels of erythrocyte sedimentation rate (ESR)","correct":false,"visible":false},{"text":"Fine needle aspiration cytology (FNAC)","correct":false,"visible":false},{"text":"Excisional biopsy of the node","correct":true,"visible":false},{"text":"Supportive evidence by chest X-ray (CXR)","correct":false,"visible":false}]},{"id":1246,"text":"Which of the following is the correct sequence of steps in bone marrow transplantation?","explanation":null,"reference":null,"responses":[{"text":"Collection, chemotherapy, infusion","correct":false,"visible":false},{"text":"Collection, processing, cryopreservation, infusion","correct":false,"visible":false},{"text":"Collection, cryopreservation, chemotherapy, infusion","correct":false,"visible":false},{"text":"Collection, processing, cryopreservation, chemotherapy, infusion","correct":true,"visible":false},{"text":"Collection, infusion","correct":false,"visible":false}]},{"id":1251,"text":"A detective is searching for evidence at a crime scene when he encounters fingerprints on the doorknob. He takes the impressions for examination. Inspection reveals that the pattern resembles hairpin heads that are elongated in the left direction. What is the most likely fingerprint pattern in this case?","explanation":null,"reference":"1) Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 85.\r\n2) D'24 slides; Hematology module, Forensic-medicine lecture slides, Topic: Personal identity III; Sub-topic: Various patterns seen in fingerprints.\r\n3) Fingerprint | definition \u0026 facts | britannica. Accessed March 31, 2022. https://www.britannica.com/topic/fingerprint","responses":[{"text":"Loop","correct":true,"visible":false},{"text":"Composite","correct":false,"visible":false},{"text":"Arch","correct":false,"visible":false},{"text":"Whorl","correct":false,"visible":false},{"text":"Tented arch","correct":false,"visible":false}]},{"id":1253,"text":"Primary immune thrombocytopenia occurs due to which of the following?","explanation":null,"reference":null,"responses":[{"text":"Systemic lupus erythmatosus (SLE)","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Auto-antibodies","correct":true,"visible":false},{"text":"Lymphoma","correct":false,"visible":false},{"text":"Leukemia","correct":false,"visible":false}]},{"id":1255,"text":"A young boy is arrested due to a criminal charge. The court orders for a detailed forensic examination to determine his age. Pelvic X-ray findings show that the ischium and pubis are not united. What is the approximate age of the boy?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 72.","responses":[{"text":"Less than 18 years","correct":false,"visible":false},{"text":"Less than 7 years","correct":true,"visible":false},{"text":"25 years or more","correct":false,"visible":false},{"text":"Less than 12 years","correct":false,"visible":false},{"text":"Less than 25 years","correct":false,"visible":false}]},{"id":1257,"text":"A 21-year-old female presents with petechiae on her skin and episodes of epistaxis for the last two months. On examination, there is no hepatosplenomegaly or lymphadenopathy. Which of the following is the most sensitive earliest test for making a diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 656, 657.","responses":[{"text":"Antinuclear antibody (ANA) profile","correct":false,"visible":false},{"text":"Reticulocyte count","correct":false,"visible":false},{"text":"Platelet count","correct":true,"visible":false},{"text":"Liver function test","correct":false,"visible":false},{"text":"Bone marrow aspiration","correct":false,"visible":false}]},{"id":1258,"text":"A 35-year-old male known case of chronic myeloid leukemia shows massive splenomegaly on clinical examination. Complete blood count (CBC) reveals WBC count=165x10^9/L, Hb= 9.0 gm/dL and platelets=510 X10^3. Which of the following targeted therapy is specific for chronic myeloid leukemia patients?","explanation":null,"reference":null,"responses":[{"text":"Jak-2 inhibitors","correct":false,"visible":false},{"text":"Anti-CD20 antibody","correct":false,"visible":false},{"text":"Check point inhibitors","correct":false,"visible":false},{"text":"Tyrosine kinase inhibitors","correct":true,"visible":false},{"text":"Thrombopoietin receptor agonists","correct":false,"visible":false}]},{"id":1262,"text":"A 60-year-old patient presented with anorexia, weakness, paraesthesia, and mental changes. His tongue was red, tendon reflexes were diminished, and hemoglobin was 6 gm/dL with large red cells and hypersegmented neutrophils. Endoscopy revealed atrophic gastritis. Deficiency of which factor is likely to be responsible for his condition?","explanation":null,"reference":null,"responses":[{"text":"Vitamin E","correct":false,"visible":false},{"text":"Vitamin B12","correct":true,"visible":false},{"text":"Riboflavin","correct":false,"visible":false},{"text":"Folic acid","correct":false,"visible":false},{"text":"Pyridoxine","correct":false,"visible":false}]},{"id":1267,"text":"The age of a young boy needs to be determined. Dental X-ray reveals mixed dentition and examination of the oral cavity reveals that the first molars have erupted. What is the approximate age of this boy?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 69.","responses":[{"text":"5-7 years","correct":false,"visible":false},{"text":"16-18 years","correct":false,"visible":false},{"text":"10-12 years","correct":false,"visible":false},{"text":"6-9 years","correct":false,"visible":false},{"text":"6-7 years","correct":true,"visible":false}]},{"id":1268,"text":"The approximate age of a girl needs to be determined as ordered by the court. After getting a series of X-rays done, it is revealed that she has only 3 carpal bones ossified. What is the likely age of the girl?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 73.","responses":[{"text":"10","correct":false,"visible":false},{"text":"1","correct":false,"visible":false},{"text":"6","correct":false,"visible":false},{"text":"7","correct":false,"visible":false},{"text":"3","correct":true,"visible":false}]},{"id":1271,"text":"A 2-year-old boy presents with a history of anemia. His spleen is just palpable. Lab findings reveal Hb=10 gm/dL, MCV=67 fL, high HbA2 (7%), normal HbF, and a normal iron profile. Which of the following best corresponds to this clinical picture?","explanation":null,"reference":null,"responses":[{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Beta-thalassemia minor","correct":true,"visible":false},{"text":"Alpha-thalassemia","correct":false,"visible":false},{"text":"Anemia of chronic disease","correct":false,"visible":false},{"text":"Beta-thalassemia major","correct":false,"visible":false}]},{"id":4509,"text":"A person undergoes ileal resection. After some days he develops weakness, shortness of breath, and anemia. Which anemia can it possibly be?","explanation":"After ileal resection, the absorption of vitamin B12 is impaired since the ileum is responsible for the absorption of this essential vitamin. Vitamin B12 is required for the synthesis of DNA and normal red blood cell maturation. Therefore, a deficiency of vitamin B12 leads to **megaloblastic anemia**.\r\n\r\nMegaloblastic anemia is characterized by the presence of large, immature red blood cells (megaloblasts) in the bone marrow. These cells have impaired DNA synthesis, leading to delayed maturation. The result is fewer and larger red blood cells in circulation.\r\n\r\nClinical manifestations of megaloblastic anemia include weakness, shortness of breath, and anemia symptoms due to decreased oxygen-carrying capacity of the blood. Other symptoms may include pale skin, fatigue, and neurological manifestations such as numbness and tingling in the extremities.\r\n\r\nSupplementation of vitamin B12 is necessary to correct the deficiency and alleviate the symptoms of megaloblastic anemia.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 45.","responses":[{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Pernicious anemia","correct":false,"visible":false},{"text":"Megaloblastic anemia","correct":true,"visible":false},{"text":"Iron deficiency anemia","correct":false,"visible":false},{"text":"Chronic blood loss anemia","correct":false,"visible":false}]},{"id":4521,"text":"Which interleukin is required for the growth and proliferation of all the stem cells?","explanation":"**Interleukin-3 (IL-3)** is a cytokine that plays a crucial role in the growth and proliferation of stem cells. IL-3 is produced by various cells, including activated T cells and mast cells, and acts on hematopoietic stem cells in the bone marrow. \r\n\r\nIL-3 stimulates the production and differentiation of multiple blood cell lineages, including red blood cells, white blood cells, and platelets. It acts as a growth factor for early progenitor cells, promoting their survival, proliferation, and differentiation into specific cell types. By supporting the growth of stem cells, IL-3 helps to maintain a healthy and functional hematopoietic system.\r\n\r\nWhile other interleukins, such as IL-1, IL-4, IL-5, and IL-2, also play important roles in immune regulation and hematopoiesis, IL-3 is specifically known for its broad effects on stem cell growth and proliferation.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 441.","responses":[{"text":"Interleukin-2","correct":false,"visible":false},{"text":"Interleukin-3","correct":true,"visible":false},{"text":"Interleukin-1","correct":false,"visible":false},{"text":"Interleukin-5","correct":false,"visible":false},{"text":"Interleukin-4","correct":false,"visible":false}]},{"id":10813,"text":"A 25-year-old pregnant woman is found to have microcytic anemia during her antenatal visits. Her Hb is 7 mg/dL with an MCV of 66 fL. Which of the following is the single best test for the confirmation of iron deficiency anemia?","explanation":null,"reference":"(1) Jameson JL, Fauci AS, Kasper DL, Hauser SL, Longo DL, Loscalzo J, eds. Harrison’s Principles of Internal Medicine. 20th ed. McGraw-Hill Education; 2018: 685.\r\n\r\n(2) Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 952.","responses":[{"text":"Serum ferritin levels","correct":true,"visible":false},{"text":"Transferrin saturation","correct":false,"visible":false},{"text":"Total iron binding capacity (TIBC)","correct":false,"visible":false},{"text":"Serum iron levels","correct":false,"visible":false},{"text":"Hb electrophoresis","correct":false,"visible":false}]},{"id":10814,"text":"A 30-year-old man presents with a history of hematuria for 15 days. He also had an episode of gum bleed one day back. Considering idiopathic thrombocytopenic purpura (ITP) as the diagnosis, which of the following is the best initial treatment of choice?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 971.","responses":[{"text":"Thrombopoietin agonist","correct":false,"visible":false},{"text":"Danazole","correct":false,"visible":false},{"text":"Plasmapheresis","correct":false,"visible":false},{"text":"Splenectomy","correct":false,"visible":false},{"text":"Corticosteroids","correct":true,"visible":false}]},{"id":10815,"text":"A 57-year-old man presents with hypertrophy of gums and is diagnosed with acute myeloid leukemia (AML). Which of the following is characteristic of this condition?","explanation":null,"reference":"Jameson JL, Fauci AS, Kasper DL, Hauser SL, Longo DL, Loscalzo J, eds. Harrison’s Principles of Internal Medicine. 20th ed. McGraw-Hill Education; 2018: 743.","responses":[{"text":"Auer rods","correct":true,"visible":false},{"text":"Ringed sideroblasts","correct":false,"visible":false},{"text":"Reed-Sternberg cells","correct":false,"visible":false},{"text":"Burr cells","correct":false,"visible":false},{"text":"Howell Jolly bodies","correct":false,"visible":false}]},{"id":10856,"text":"A 34-year-old woman presents to the clinic with pallor, jaundice, and splenomegaly. Her complete blood count shows Hb 9 g/dL and MCV 107 fL. Direct Coomb's test is positive. She is diagnosed with warm autoimmune hemolytic anemia and treated with steroids, but the patient does not respond. Which of the following is the next best step in management?","explanation":"**Rituximab** is now the recommended second-line therapy for warm autoimmune hemolytic anemia (AIHA) in patients who do not respond to steroids. Rituximab is a monoclonal antibody against CD20, which is found on the surface of B-lymphocytes. It causes B-cell depletion and has been shown to be effective in steroid-refractory cases of AIHA.\r\n\r\n---\r\n\r\nSplenectomy is considered if there is no response after a trial of steroids and rituximab, or in cases of severe or life-threatening hemolysis. Cyclophosphamide and azathioprine are immunosuppressive agents that may be used in refractory cases, but they are not typically the next line of treatment after steroids. Transfusion is supportive care, not a treatment, and is given in cases of severe anemia to manage symptoms but does not address the underlying autoimmune process. It's also approached with caution due to the risk of hemolysis and alloimmunization.","reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022.","responses":[{"text":"Transfusion","correct":false,"visible":false},{"text":"Azathioprine","correct":false,"visible":false},{"text":"Cyclophosphamide","correct":false,"visible":false},{"text":"Rituximab","correct":true,"visible":false},{"text":"Splenectomy","correct":false,"visible":false}]},{"id":10858,"text":"A 60-year-old woman presents with a 4-month history of progressive lethargy and recurrent throat infections. Recently, she developed gum bleeding and noticed purpura all over her body. She is anemic, but the remainder of the examination is normal. Investigations show Hb 7 g/dL, white cell count 83000/uL, and platelets 18000/uL. Bone marrow biopsy shows hypercellular marrow with a decrease in normal precursor cells.; 85% of the cells are myeloblasts. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Davidson's principles and practice of medicine 23rd edition, pg. 956","responses":[{"text":"Chronic myeloid leukemia","correct":false,"visible":false},{"text":"Lymphoma","correct":false,"visible":false},{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Acute myeloid leukemia","correct":true,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false}]},{"id":10863,"text":"A 50-year-old man presents to the clinic with marked heaviness in the left hypochondrium. He has also had experienced early satiety for 3 months. On examination, the liver is enlarged, 3 cm below the costal margin amd the spleen is massively enlarged up to the umbilicus. Considering myelofibrosis as a diagnosis, which of the following is the only approved treatment?","explanation":null,"reference":"Davdison's principles and practice of medicine 24th edition, pg. 980","responses":[{"text":"Immunotherapy","correct":false,"visible":false},{"text":"Interferon","correct":false,"visible":false},{"text":"Bone marrow transplantation","correct":false,"visible":false},{"text":"Ruxolitinib","correct":true,"visible":false},{"text":"Platelet aggregation inhibitor","correct":false,"visible":false}]},{"id":10878,"text":"A 16-year-old boy is brought to the clinic with generalized weakness and easy bruising. His complete blood profile shows pancytopenia. Peripheral film shows giant metamyelocytes with large sausage-shaped nuclei. His bilirubin is  3 mg%. The reticulocyte count is 0.5%. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Davdison's principles and practice of medicine 24th edition, pg. 953","responses":[{"text":"Malaria","correct":false,"visible":false},{"text":"Acute leukemia","correct":false,"visible":false},{"text":"Megaloblastic anemia","correct":true,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Hemolytic anemia","correct":false,"visible":false}]},{"id":11007,"text":"A 79-year-old woman presents to the emergency department with complaints of confusion, headache, and tinnitus. Her general practitioner has recently started her on an analgesic; the physician on duty is worried she may have taken too much. Which of the following would most likely explain her symptoms?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 516.","responses":[{"text":"Paracetamol","correct":false,"visible":false},{"text":"Mefanamic acid","correct":false,"visible":false},{"text":"Codeine","correct":false,"visible":false},{"text":"Diclofenac sodium","correct":false,"visible":false},{"text":"Aspirin","correct":true,"visible":false}]},{"id":11008,"text":"A 68-year-old woman comes to the physician because of a history of easy fatigability and back pain. On examination, she is anemic and has tender bones. Her initial investigations show Hb 9.8 g/dL, MCV 84 fl, platelets 141 x 10^3/L, creatinine 2.3 mg/dL, ALP 84 IU, and SGPT 32 IU. Bone scan shows lytic lesions. Which of the following is the next best step in diagnosis?","explanation":null,"reference":"Harrison's principles of internal medicine, 20th edition, pg. 797, 799 (table 107-2)","responses":[{"text":"Serum protein electrophoresis","correct":true,"visible":false},{"text":"Urinary immune fixation","correct":false,"visible":false},{"text":"Serum immune fixation","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false},{"text":"Urinary protein electrophoresis","correct":false,"visible":false}]},{"id":13776,"text":"A 25-year-old female is diagnosed with porphyria variegate. Which of the following may be included as part of the specific management of this condition?","explanation":null,"reference":"Davidson's principles and practice of medicine 23rd edition, pg. 379","responses":[{"text":"Courses of venesection","correct":false,"visible":false},{"text":"Use of beta carotene","correct":false,"visible":false},{"text":"Intravenous glucose as provision of 55 KJ per day","correct":false,"visible":false},{"text":"Avoidance of agents that can precipitate the condition","correct":true,"visible":false},{"text":"Use of sunscreens","correct":false,"visible":false}]},{"id":13914,"text":"A 50-year-old female who has recently been diagnosed with hypertension presents to the clinic for a routine follow-up examination. On workup, she has abnormal values of hemoglobin (Hb) 7.4 mg/dl, MCV 84 fl, creatinine 5.4 mg/dl, blood urea nitrogen (BUN) 65 mmol/L, potassium 5.2 mEq/L, sodium 130 mEq/L, phosphorus 5.0 mEq/L, calcium 6.7 mg/dl. Which of the following is the most likely cause of decreased Hb in this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine 23rd edition, pg. 386","responses":[{"text":"Drug-induced gastritis","correct":false,"visible":false},{"text":"Iron deficiency","correct":false,"visible":false},{"text":"B12 deficiency","correct":false,"visible":false},{"text":"Deficiency of erythropoietin","correct":true,"visible":false},{"text":"Folic acid deficiency","correct":false,"visible":false}]},{"id":13942,"text":"A 16-year-old boy presents to the emergency department with the complaint of swelling of the right knee joint after trivial trauma. History is significant for similar incidences over the past 4 years. Their family history is positive for a bleeding disorder. Investigations show: hemoglobin -  10 g/dL, white cell count - 5,000/uL, platelets - 200,000/uL, factor VIII - normal, prothrombin time (PT) - 16 seconds (control - 14 seconds), activated partial thromboplastin time (APTT) - 48 seconds (control - 35 seconds). Which of the following is the most likely diagnosis?","explanation":null,"reference":"First Aid 2022, pg. 433","responses":[{"text":"Von willebrand disease","correct":false,"visible":false},{"text":"Acquired hemophilia","correct":false,"visible":false},{"text":"Hemophilia A","correct":false,"visible":false},{"text":"Hemophilia B","correct":true,"visible":false},{"text":"Glanzmann thrombasthenia","correct":false,"visible":false}]},{"id":14103,"text":"A 40-year-old man presents with easy fatigability. Investigations reveal hemoglobin (Hb) - 9 g/dL, mean corpuscular volume (MCV) - 105 fL, and spherocytes on peripheral blood film. Which of the following is the most common abnormality in hereditary spherocytosis?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 956","responses":[{"text":"Protein 4.1 deficiency","correct":false,"visible":false},{"text":"Adducin deficiency","correct":false,"visible":false},{"text":"Beta-spectrin deficiency","correct":true,"visible":false},{"text":"Alpha-spectrin deficiency","correct":false,"visible":false},{"text":"Glycophorin C deficiency","correct":false,"visible":false}]},{"id":14118,"text":"A 45-year-old male presents to you with complaints of early satiety and heaviness for the past 2 months. He also gives history of blurring of vision and severe headache for the past week. His labs show hemoglobin - 10.1 mg/dL, white blood cells - 79,000/mm3, platelets - 950,000 and left myeloid shift on peripheral smear. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 958-959.","responses":[{"text":"Myelofibrosis","correct":false,"visible":false},{"text":"Polycythemia vera rubra","correct":false,"visible":false},{"text":"Myelodysplastic syndrome","correct":false,"visible":false},{"text":"Essential thrombocytopenia","correct":false,"visible":false},{"text":"Chronic myeloid leukemia","correct":true,"visible":false}]},{"id":14120,"text":"A 10-year-old boy presents to you with a complaint of severe pain in his hands and feet. He is febrile, mildly jaundiced, and dehydrated. Labs show hemoglobin 0 5.6 gm/dL, reticulocyte count - 8%, total bilirubin - 2.5 mg, SGPT - 20. Family history is significant for a similar illness in his brother 1 year ago. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 960","responses":[{"text":"Thalassemia","correct":false,"visible":false},{"text":"Sickle cell trait","correct":false,"visible":false},{"text":"Aplastic anemia","correct":false,"visible":false},{"text":"Acute hepatitis","correct":false,"visible":false},{"text":"Sickle cell disease with vaso-occlusive crisis","correct":true,"visible":false}]},{"id":14125,"text":"Which of the following is the most common site for extrapulmonary tuberculosis?","explanation":null,"reference":"Davidson's principles and practice of medicine 24th edition, pg. 519.","responses":[{"text":"Central nervous system","correct":false,"visible":false},{"text":"Pericardium","correct":false,"visible":false},{"text":"Bones and joint","correct":false,"visible":false},{"text":"Gastrointestinal tract","correct":false,"visible":false},{"text":"Lymph nodes","correct":true,"visible":false}]},{"id":14152,"text":"Which of the following is true regarding paroxysmal nocturnal hemoglobinuria (PNH)?","explanation":null,"reference":"(1) Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 950-951.\r\n\r\n(2) Sun L, Babushok DV. Secondary myelodysplastic syndrome and leukemia in acquired aplastic anemia and paroxysmal nocturnal hemoglobinuria. Blood. Published July 2, 2020. https://pubmed.ncbi.nlm.nih.gov/32430502/","responses":[{"text":"Thrombosis is uncommon in PNH","correct":false,"visible":false},{"text":"Flow cytometry does not help in diagnosis","correct":false,"visible":false},{"text":"It does not progress to myelodysplasia or acute myeloid leukemia","correct":false,"visible":false},{"text":"It causes persistent hemoglobinuria","correct":false,"visible":false},{"text":"It can be suspected in confusing cases of hemolytic anemia or pancytopenia","correct":true,"visible":false}]},{"id":14164,"text":"A 16-year-old male presents to you with complaints of fatigue, backache, leg pain, and fever. His labs show hemoglobin of 7 g/dL. Which of the following is the definitive diagnostic test for sickle cell anemia?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 961","responses":[{"text":"Genetic screening of parents","correct":false,"visible":false},{"text":"Hemoglobin electrophoresis","correct":true,"visible":false},{"text":"Sickle solubility test","correct":false,"visible":false},{"text":"Sickle shaped cells on blood film","correct":false,"visible":false},{"text":"Reticulocytosis","correct":false,"visible":false}]},{"id":14170,"text":"An 18-year-old boy presents to the clinic and you observe on examination rubbery lymph nodes in the cervical and axillary region, along with a history of weight loss for the past 4 months. Which of the following is the gold standard test for establishing the diagnosis of this patient?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 972","responses":[{"text":"Lymph node biopsy","correct":true,"visible":false},{"text":"CT scan abdomen","correct":false,"visible":false},{"text":"CT scan neck","correct":false,"visible":false},{"text":"CT scan chest","correct":false,"visible":false},{"text":"Bone marrow biopsy","correct":false,"visible":false}]},{"id":14173,"text":"Which of the following is a poor source of folic acid?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 954","responses":[{"text":"Kidney","correct":false,"visible":false},{"text":"Eggs","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Bananas","correct":false,"visible":false},{"text":"Green leafy vegetable","correct":false,"visible":false}]},{"id":14177,"text":"Which of the following is not an indication of anticoagulation therapy?","explanation":null,"reference":"Shahpouri MM, Mousavi S, Khorvash F, Mousavi SM, Hoseini T. Anticoagulant therapy for ischemic stroke: A review of literature. J Res Med Sci. 2012;17(4):396-401. Accessed January 5, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3526137/","responses":[{"text":"Intracardiac thrombus","correct":false,"visible":false},{"text":"Internal carotid artery thrombus","correct":false,"visible":false},{"text":"Protein C or protein S deficiency","correct":false,"visible":false},{"text":"Acute stroke secondary to hypertension","correct":true,"visible":false},{"text":"Stroke resulting from atrial fibrillation","correct":false,"visible":false}]},{"id":14257,"text":"A 65-year-old man presents to the hematology outpatient department with a 6 months history of tiredness, weight loss, and shortness of breath. On examination, there is massive splenomegaly but no lymphadenopathy. Lab investigations show hemoglobin - 9.8 g/dL, white blood cells - 240,000/mm3, and platelets - 458,000/mm3. Peripheral blood film shows increased number of neutrophils and myelocytes with prominent basophils and normocytic normochromic red blood cells. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Davidson's principles and practice of medicine, 24th edition, pg. 968","responses":[{"text":"Hodgkin lymphoma","correct":false,"visible":false},{"text":"Chronic myeloid leukemia","correct":true,"visible":false},{"text":"Chronic lymphocytic leukemia","correct":false,"visible":false},{"text":"Acute lymphoblastic leukemia","correct":false,"visible":false},{"text":"Acute myeloid leukemia","correct":false,"visible":false}]}
]

export default a